  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Thin HTTP adapter. Parses request, resolves workspace, delegates to
  5→ * the observer agent for all verification logic (deterministic + LLM).
  6→ */
  7→
  8→import { RecordId, type Surreal } from "surrealdb";
  9→import type { LanguageModel } from "ai";
 10→import { jsonResponse } from "../http/response";
 11→import { logError, logInfo } from "../http/observability";
 12→import type { ServerDependencies } from "../runtime/types";
 13→import { runObserverAgent } from "../agents/observer/agent";
 14→import { runGraphScan } from "./graph-scan";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→const SUPPORTED_TABLES = new Set<string>([
 21→  "task",
 22→  "intent",
 23→  "git_commit",
 24→  "decision",
 25→  "observation",
 26→]);
 27→
 28→// ---------------------------------------------------------------------------
 29→// Route handler factory
 30→// ---------------------------------------------------------------------------
 31→
 32→export function createObserverRouteHandler(deps: ServerDependencies) {
 33→  return async (table: string, id: string, request: Request): Promise<Response> => {
 34→    if (!SUPPORTED_TABLES.has(table)) {
 35→      return jsonResponse({ error: "unsupported_table", table }, 400);
 36→    }
 37→
 38→    try {
 39→      const body = await request.json().catch(() => undefined);
 40→
 41→      logInfo("observer.event.received", "Observer event received", { table, id });
 42→
 43→      // Resolve workspace
 44→      const workspaceId = await resolveWorkspaceId(deps.surreal, table, id, body);
 45→      if (!workspaceId) {
 46→        logError("observer.event.no_workspace", "Cannot determine workspace", { table, id });
 47→        return jsonResponse({ status: "ok" }, 200);
 48→      }
 49→
 50→      const workspaceRecord = new RecordId("workspace", workspaceId);
 51→
 52→      // Delegate to observer agent
 53→      const agentOutput = await runObserverAgent({
 54→        surreal: deps.surreal,
 55→        workspaceRecord,
 56→        entityTable: table,
 57→        entityId: id,
 58→        entityBody: body,
 59→        observerModel: deps.observerModel as LanguageModel | undefined,
 60→      });
 61→
 62→      logInfo(`observer.${table}.verified`, `${table} verification complete`, {
 63→        [`${table}Id`]: id,
 64→        verdict: agentOutput.verdict,
 65→        observationsCreated: agentOutput.observations_created,
 66→        evidence: agentOutput.evidence,
 67→      });
 68→
 69→      return jsonResponse({ status: "ok" }, 200);
 70→    } catch (error) {
 71→      logError("observer.event.error", "Observer event processing failed", error);
 72→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
 73→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
 74→    }
 75→  };
 76→}
 77→
 78→// ---------------------------------------------------------------------------
 79→// Graph scan route handler factory
 80→// ---------------------------------------------------------------------------
 81→
 82→export function createGraphScanRouteHandler(deps: ServerDependencies) {
 83→  return async (workspaceId: string, _request: Request): Promise<Response> => {
 84→    try {
 85→      const observerModel = deps.observerModel as LanguageModel | undefined;
 86→      if (!observerModel) {
 87→        return jsonResponse({ error: "observer_model_required", message: "OBSERVER_MODEL env var is required for graph scan" }, 503);
 88→      }
 89→
 90→      logInfo("observer.scan.started", "Graph scan triggered", { workspaceId });
 91→
 92→      const workspaceRecord = new RecordId("workspace", workspaceId);
 93→      const result = await runGraphScan(deps.surreal, workspaceRecord, observerModel);
 94→
 95→      return jsonResponse({ status: "ok", ...result }, 200);
 96→    } catch (error) {
 97→      logError("observer.scan.error", "Graph scan failed", error);
 98→      return jsonResponse({ status: "error", message: "scan failed" }, 500);
 99→    }
100→  };
101→}
102→
103→// ---------------------------------------------------------------------------
104→// Workspace resolution
105→// ---------------------------------------------------------------------------
106→
107→const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
108→
109→async function resolveWorkspaceId(
110→  surreal: Surreal,
111→  table: string,
112→  id: string,
113→  body?: Record<string, unknown>,
114→): Promise<string | undefined> {
115→  let wsId: string | undefined;
116→
117→  if (body?.workspace) {
118→    const ws = body.workspace;
119→    if (typeof ws === "string") {
120→      const cleaned = ws.replace(/`/g, "");
121→      wsId = cleaned.includes(":") ? cleaned.split(":")[1] : cleaned;
122→    } else if (typeof ws === "object" && ws !== null) {
123→      const wsObj = ws as { id?: string | { String?: string } };
124→      if (typeof wsObj.id === "string") wsId = wsObj.id.replace(/`/g, "");
125→      else if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
126→        wsId = (wsObj.id as { String: string }).String.replace(/`/g, "");
127→      }
128→    }
129→  }
130→
131→  // Fallback: query the DB
132→  if (!wsId) {
133→    const record = new RecordId(table, id);
134→    const [rows] = await surreal.query<
135→      [Array<{ workspace: RecordId<"workspace", string> }>]
136→    >(
137→      `SELECT workspace FROM $record;`,
138→      { record },
139→    );
140→    wsId = rows?.[0]?.workspace ? (rows[0].workspace.id as string) : undefined;
141→  }
142→
143→  if (wsId && !UUID_PATTERN.test(wsId)) {
144→    throw new Error(`Invalid workspace ID format: ${wsId}`);
145→  }
146→
147→  return wsId;
148→}
149→

