  1→/**
  2→ * Milestone 2: Verification Pipeline
  3→ *
  4→ * Traces: Story 1 (Task Verification), Story 2 (Intent Verification),
  5→ *         Story 2b (Commit Verification), Story 3 (Graceful Degradation)
  6→ *
  7→ * Validates the core claim-vs-reality comparison:
  8→ * - match -> observation severity: info, verified: true
  9→ * - mismatch -> observation severity: conflict, verified: false
 10→ * - inconclusive -> observation severity: info, note missing source
 11→ * - External API failures do NOT block the original workflow
 12→ *
 13→ * Driving ports:
 14→ *   POST /api/observe/task/:id
 15→ *   POST /api/observe/intent/:id
 16→ *   POST /api/observe/git_commit/:id
 17→ */
 18→import { describe, expect, it, beforeAll, afterAll } from "bun:test";
 19→import { RecordId } from "surrealdb";
 20→import {
 21→  setupObserverSuite,
 22→  wireObserverEvents,
 23→  setupObserverWorkspace,
 24→  createTaskWithCommit,
 25→  createCompletedIntent,
 26→  createGitCommit,
 27→  triggerTaskCompletion,
 28→  triggerIntentCompletion,
 29→  waitForObservation,
 30→  getWorkspaceObservations,
 31→  createMockGitHubServer,
 32→} from "./observer-test-kit";
 33→
 34→const getRuntime = setupObserverSuite("observer_m2_verification");
 35→
 36→beforeAll(async () => {
 37→  const { surreal, port } = getRuntime();
 38→  await wireObserverEvents(surreal, port);
 39→});
 40→
 41→// =============================================================================
 42→// Story 1: Task Completion Verification
 43→// =============================================================================
 44→
 45→describe("Milestone 2: Task Completion Verification (Story 1)", () => {
 46→  // ---------------------------------------------------------------------------
 47→  // S1-1: Task with passing CI -> observation severity info, verified true
 48→  // ---------------------------------------------------------------------------
 49→  it("task linked to passing CI produces a verified observation", async () => {
 50→    const { baseUrl, surreal } = getRuntime();
 51→
 52→    // Given a workspace with a task linked to a commit with passing CI
 53→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "verify-pass");
 54→    const sha = `abc${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
 55→
 56→    // Set up a mock GitHub server that reports success for this commit
 57→    const mockGitHub = createMockGitHubServer([
 58→      {
 59→        path: `/repos/org/brain/commits/${sha}/status`,
 60→        status: 200,
 61→        body: { state: "success", statuses: [], total_count: 1 },
 62→      },
 63→    ]);
 64→
 65→    // Point the observer at our mock GitHub
 66→    const originalUrl = process.env.GITHUB_API_URL;
 67→    process.env.GITHUB_API_URL = mockGitHub.url;
 68→
 69→    try {
 70→      const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
 71→        title: "Add rate limiting to API gateway",
 72→        status: "in_progress",
 73→        sha,
 74→        repository: "org/brain",
 75→      });
 76→
 77→      // When the task is marked as completed
 78→      await triggerTaskCompletion(surreal, taskId);
 79→
 80→      // Then the observer creates a verified observation
 81→      const observations = await waitForObservation(surreal, "task", taskId, 30_000);
 82→      expect(observations.length).toBeGreaterThanOrEqual(1);
 83→
 84→      const obs = observations[0];
 85→      expect(obs.severity).toBe("info");
 86→      expect(obs.verified).toBe(true);
 87→      expect(obs.source_agent).toBe("observer_agent");
 88→      // And the observation records the external signal source
 89→      expect(obs.source).toBeTruthy();
 90→    } finally {
 91→      mockGitHub.stop();
 92→      if (originalUrl !== undefined) {
 93→        process.env.GITHUB_API_URL = originalUrl;
 94→      } else {
 95→        delete process.env.GITHUB_API_URL;
 96→      }
 97→    }
 98→  }, 120_000);
 99→
100→  // ---------------------------------------------------------------------------
101→  // S1-2: Task with failing CI -> observation severity conflict, verified false
102→  // ---------------------------------------------------------------------------
103→  it("task linked to failing CI produces a conflict observation", async () => {
104→    const { baseUrl, surreal } = getRuntime();
105→
106→    // Given a workspace with a task linked to a commit with failing CI
107→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "verify-fail");
108→    const sha = `def${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
109→
110→    // Set up a mock GitHub server that reports failure for this commit
111→    const mockGitHub = createMockGitHubServer([
112→      {
113→        path: `/repos/org/brain/commits/${sha}/status`,
114→        status: 200,
115→        body: { state: "failure", statuses: [{ state: "failure" }], total_count: 1 },
116→      },
117→    ]);
118→
119→    // Point the observer at our mock GitHub
120→    const originalUrl = process.env.GITHUB_API_URL;
121→    process.env.GITHUB_API_URL = mockGitHub.url;
122→
123→    try {
124→      const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
125→        title: "Refactor authentication middleware",
126→        status: "in_progress",
127→        sha,
128→        repository: "org/brain",
129→      });
130→
131→      // When the task is marked as completed despite failing CI
132→      await triggerTaskCompletion(surreal, taskId);
133→
134→      // Then the observer creates a conflict observation flagging the mismatch
135→      const observations = await waitForObservation(surreal, "task", taskId, 30_000);
136→      expect(observations.length).toBeGreaterThanOrEqual(1);
137→
138→      const obs = observations[0];
139→      expect(obs.severity).toBe("conflict");
140→      expect(obs.verified).toBe(false);
141→      expect(obs.source_agent).toBe("observer_agent");
142→      expect(obs.text).toBeTruthy();
143→    } finally {
144→      mockGitHub.stop();
145→      if (originalUrl !== undefined) {
146→        process.env.GITHUB_API_URL = originalUrl;
147→      } else {
148→        delete process.env.GITHUB_API_URL;
149→      }
150→    }
151→  }, 120_000);
152→
153→  // ---------------------------------------------------------------------------
154→  // S1-3: Task with no external signals -> inconclusive observation
155→  // ---------------------------------------------------------------------------
156→  it("task with no external signals produces an inconclusive observation", async () => {
157→    const { baseUrl, surreal } = getRuntime();
158→
159→    // Given a workspace with a task that has no linked commits or PRs
160→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "verify-none");
161→    const taskId = `task-${crypto.randomUUID()}`;
162→    const taskRecord = new RecordId("task", taskId);
163→    const wsRecord = new RecordId("workspace", workspaceId);
164→
165→    await surreal.query(`CREATE $task CONTENT $content;`, {
166→      task: taskRecord,
167→      content: {
168→        title: "Update team onboarding documentation",
169→        description: "No code changes involved",
170→        status: "in_progress",
171→        workspace: wsRecord,
172→        created_at: new Date(),
173→        updated_at: new Date(),
174→      },
175→    });
176→
177→    // When the task is marked as completed
178→    await triggerTaskCompletion(surreal, taskId);
179→
180→    // Then the observer creates an informational observation noting missing signals
181→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
182→    expect(observations.length).toBeGreaterThanOrEqual(1);
183→
184→    const obs = observations[0];
185→    expect(obs.severity).toBe("info");
186→    expect(obs.source_agent).toBe("observer_agent");
187→    // And the observation notes that verification was inconclusive
188→    expect(obs.text.toLowerCase()).toMatch(/inconclusive|no external|unable to verify/);
189→  }, 120_000);
190→});
191→
192→// =============================================================================
193→// Story 2: Intent Completion Verification
194→// =============================================================================
195→
196→describe("Milestone 2: Intent Completion Verification (Story 2)", () => {
197→  // ---------------------------------------------------------------------------
198→  // S2-1: Intent completed -> verification observation created
199→  // ---------------------------------------------------------------------------
200→  it("completed intent produces a verification observation", async () => {
201→    const { baseUrl, surreal } = getRuntime();
202→
203→    // Given a workspace with an intent that has been authorized
204→    const { workspaceId, identityId } = await setupObserverWorkspace(baseUrl, surreal, "intent-verify");
205→
206→    const intentId = `intent-${crypto.randomUUID()}`;
207→    const intentRecord = new RecordId("intent", intentId);
208→    const wsRecord = new RecordId("workspace", workspaceId);
209→    const requesterRecord = new RecordId("identity", identityId);
210→    const traceRecord = new RecordId("trace", `trace-${intentId}`);
211→
212→    await surreal.query(`CREATE $trace CONTENT $content;`, {
213→      trace: traceRecord,
214→      content: { type: "intent_submission", actor: requesterRecord, workspace: wsRecord, created_at: new Date() },
215→    });
216→
217→    await surreal.query(`CREATE $intent CONTENT $content;`, {
218→      intent: intentRecord,
219→      content: {
220→        goal: "Add input validation to user registration",
221→        reasoning: "Prevent malformed data from entering the system",
222→        status: "executing",
223→        priority: 50,
224→        action_spec: { provider: "file_editor", action: "edit_file", params: { target: "src/auth/register.ts" } },
225→        trace_id: traceRecord,
