232→
233→    // When the intent transitions to completed
234→    await triggerIntentCompletion(surreal, intentId, "completed");
235→
236→    // Then the observer creates an observation linked to the intent
237→    const observations = await waitForObservation(surreal, "intent", intentId, 30_000);
238→    expect(observations.length).toBeGreaterThanOrEqual(1);
239→
240→    const obs = observations[0];
241→    expect(obs.source_agent).toBe("observer_agent");
242→    expect(obs.severity).toBeDefined();
243→  }, 120_000);
244→
245→  // ---------------------------------------------------------------------------
246→  // S2-2: Intent failed -> observation records failure
247→  // ---------------------------------------------------------------------------
248→  it("failed intent produces an observation recording the failure", async () => {
249→    const { baseUrl, surreal } = getRuntime();
250→
251→    // Given a workspace with an intent that was executing
252→    const { workspaceId, identityId } = await setupObserverWorkspace(baseUrl, surreal, "intent-fail");
253→
254→    const intentId = `intent-${crypto.randomUUID()}`;
255→    const intentRecord = new RecordId("intent", intentId);
256→    const wsRecord = new RecordId("workspace", workspaceId);
257→    const requesterRecord = new RecordId("identity", identityId);
258→    const traceRecord = new RecordId("trace", `trace-${intentId}`);
259→
260→    await surreal.query(`CREATE $trace CONTENT $content;`, {
261→      trace: traceRecord,
262→      content: { type: "intent_submission", actor: requesterRecord, workspace: wsRecord, created_at: new Date() },
263→    });
264→
265→    await surreal.query(`CREATE $intent CONTENT $content;`, {
266→      intent: intentRecord,
267→      content: {
268→        goal: "Deploy to staging environment",
269→        reasoning: "Pre-production validation required",
270→        status: "executing",
271→        priority: 60,
272→        action_spec: { provider: "deploy", action: "staging" },
273→        trace_id: traceRecord,
274→        requester: requesterRecord,
275→        workspace: wsRecord,
276→        evaluation: { decision: "APPROVE", risk_score: 40, reason: "Moderate risk deployment", evaluated_at: new Date(), policy_only: false },
277→        created_at: new Date(),
278→      },
279→    });
280→
281→    // When the intent transitions to failed
282→    await triggerIntentCompletion(surreal, intentId, "failed");
283→
284→    // Then the observer creates a warning or conflict observation
285→    const observations = await waitForObservation(surreal, "intent", intentId, 30_000);
286→    expect(observations.length).toBeGreaterThanOrEqual(1);
287→
288→    const obs = observations[0];
289→    expect(obs.source_agent).toBe("observer_agent");
290→    expect(["warning", "conflict"]).toContain(obs.severity);
291→  }, 120_000);
292→});
293→
294→// =============================================================================
295→// Story 2b: Commit Verification
296→// =============================================================================
297→
298→describe("Milestone 2: Commit Verification (Story 2b)", () => {
299→  // ---------------------------------------------------------------------------
300→  // S2b-1: Commit created -> GitHub status checked, observation created
301→  // ---------------------------------------------------------------------------
302→  it("new commit triggers status verification and creates observation", async () => {
303→    const { baseUrl, surreal } = getRuntime();
304→
305→    // Given a workspace exists
306→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "commit-verify");
307→    const sha = `commit${crypto.randomUUID().replace(/-/g, "").slice(0, 34)}`;
308→
309→    // When a new git commit record is created (fires commit_created EVENT)
310→    const { commitId } = await createGitCommit(surreal, workspaceId, sha, {
311→      message: "feat: implement observer agent pipeline",
312→      repository: "org/brain",
313→    });
314→
315→    // Then the observer creates an observation for the commit
316→    const observations = await waitForObservation(surreal, "git_commit", commitId, 30_000);
317→    expect(observations.length).toBeGreaterThanOrEqual(1);
