319→    const obs = observations[0];
320→    expect(obs.source_agent).toBe("observer_agent");
321→    expect(obs.severity).toBeDefined();
322→  }, 120_000);
323→});
324→
325→// =============================================================================
326→// Story 3: Graceful Degradation
327→// =============================================================================
328→
329→describe("Milestone 2: Graceful Degradation (Story 3)", () => {
330→  // ---------------------------------------------------------------------------
331→  // S3-1: External API unreachable -> warning observation, task not blocked
332→  // ---------------------------------------------------------------------------
333→  it("external API failure produces warning observation without blocking task", async () => {
334→    const { baseUrl, surreal } = getRuntime();
335→
336→    // Given a workspace with a task linked to a commit
337→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "degrade-api");
338→    const sha = `fail${crypto.randomUUID().replace(/-/g, "").slice(0, 36)}`;
339→
340→    const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
341→      title: "Integrate third-party payment gateway",
342→      status: "in_progress",
343→      sha,
344→      repository: "org/brain",
345→    });
346→
347→    // And the external CI/GitHub API is unreachable (simulated by no mock server)
348→
349→    // When the task is marked as completed
350→    await triggerTaskCompletion(surreal, taskId);
351→
352→    // Then the observer creates a warning or info observation (not a blocking error)
353→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
354→    expect(observations.length).toBeGreaterThanOrEqual(1);
355→
356→    const obs = observations[0];
357→    expect(obs.source_agent).toBe("observer_agent");
358→    expect(["info", "warning"]).toContain(obs.severity);
359→
360→    // And the task status remains completed (observer did NOT revert it)
361→    const taskRecord = new RecordId("task", taskId);
362→    const taskRows = (await surreal.query(
363→      `SELECT status FROM $task;`,
364→      { task: taskRecord },
365→    )) as Array<Array<{ status: string }>>;
366→    expect(taskRows[0]?.[0]?.status).toBe("completed");
367→  }, 120_000);
368→
369→  // ---------------------------------------------------------------------------
370→  // S3-2: EVENT RETRY handles transient failures
371→  // ---------------------------------------------------------------------------
372→  it("transient observer endpoint failure is retried by EVENT", async () => {
373→    const { baseUrl, surreal } = getRuntime();
374→
375→    // Given a workspace with a task
376→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "degrade-retry");
377→    const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
378→      title: "Add health check endpoint",
379→      status: "in_progress",
380→    });
381→
382→    // When the task is completed (EVENT fires with RETRY 3)
383→    await triggerTaskCompletion(surreal, taskId);
384→
385→    // Then even if the first attempt encounters a transient error,
386→    // the RETRY mechanism ensures the observation is eventually created
387→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
388→    expect(observations.length).toBeGreaterThanOrEqual(1);
389→  }, 120_000);
390→});
